#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e6+5;
int n,c[maxn],sum,ans=LLONG_MAX,siz[maxn],dp[maxn],tot;
vector<pair<int,int>> g[maxn];
void dfs(int u,int fa,int s) {
	siz[u]=c[u];
	dp[1]+=c[u]*s;
	for(auto &e:g[u]) {
		int v=e.first,w=e.second;
		if(v==fa) {
			continue;
		}
		dfs(v,u,s+w);
		siz[u]+=siz[v];
	}
}
void dfs1(int u,int fa) {
	for(auto &e:g[u]) {
		int v=e.first,w=e.second;
		if(v==fa) {
			continue;
		}
		dp[v]=dp[u]+(tot-2*siz[v])*w;
		dfs1(v,u);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>c[i];
		tot+=c[i];
	}
	for(int i=1; i<n; i++) {
		int u,v,x;
		cin>>u>>v>>x;
		g[u].emplace_back(v,x);
		g[v].emplace_back(u,x);
	}
	dfs(1,0,0);
	dfs1(1,0);
	for(int i=2; i<=n; i++) {
		ans=min(ans,dp[i]);
	}
	cout<<ans;
	return 0;
}
